def solve(nums, target):
    left, right = 0, len(nums) - 1
    while left < right:
        total = nums[left] + nums[right]
        if total == target:
            return left, right
        if total < target:
            left += 1
        else:
            right -= 1
    return -1, -1

# Additional checks for pitfalls
def check_no_solution(nums, target):
    if len(nums) < 2:
        return True  # Not enough numbers to form a pair
    return False

def solve_with_checks(nums, target):
    if check_no_solution(nums, target):
        return -1, -1
    return solve(nums, target)

# Unit tests for critical behaviors
def test_solve():
    assert solve([1, 2, 3, 4, 6], 6) == (1, 3)
    assert solve([2, 7, 11, 15], 9) == (0, 1)
    assert solve([1, 2, 3, 4, 5], 10) == (-1, -1)
    assert solve([], 5) == (-1, -1)
    assert solve([1], 1) == (-1, -1)

# Adversarial/edge-case tests
def test_edge_cases():
    assert solve([1, 2, 3, 4, 5], 0) == (-1, -1)
    assert solve([1, 2, 3, 4, 5], 1) == (-1, -1)
    assert solve([1, 2, 3, 4, 5], 10) == (-1, -1)
    assert solve([-1, 0, 1, 2], 1) == (0, 2)

# Run tests
test_solve()
test_edge_cases()
